// Generated by forge proof from structured-event-log.md
import { describe, test, expect, afterEach } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import { streamLogAppend } from './core.js';
import type {
  SessionEvent,
  SessionStartEvent,
  TextDeltaEvent,
  ThinkingDeltaEvent,
  ToolCallStartEvent,
  ToolCallResultEvent,
  SessionEndEvent,
} from './types.js';

// ── Helpers ──────────────────────────────────────────────────

let tmpDirs: string[] = [];

async function makeTmpDir(): Promise<string> {
  const raw = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-core-test-'));
  const dir = await fs.realpath(raw);
  tmpDirs.push(dir);
  return dir;
}

function makeSessionStart(overrides: Partial<SessionStartEvent> = {}): SessionStartEvent {
  return {
    type: 'session_start',
    timestamp: new Date().toISOString(),
    sessionId: 'test-session-001',
    model: 'sonnet',
    prompt: 'test prompt',
    ...overrides,
  };
}

function makeTextDelta(overrides: Partial<TextDeltaEvent> = {}): TextDeltaEvent {
  return {
    type: 'text_delta',
    timestamp: new Date().toISOString(),
    content: 'Some agent text output.',
    ...overrides,
  };
}

function makeThinkingDelta(overrides: Partial<ThinkingDeltaEvent> = {}): ThinkingDeltaEvent {
  return {
    type: 'thinking_delta',
    timestamp: new Date().toISOString(),
    content: 'Analyzing the codebase...',
    ...overrides,
  };
}

function makeToolCallStart(overrides: Partial<ToolCallStartEvent> = {}): ToolCallStartEvent {
  return {
    type: 'tool_call_start',
    timestamp: new Date().toISOString(),
    toolName: 'Read',
    input: { file_path: 'src/index.ts' },
    ...overrides,
  };
}

function makeToolCallResult(overrides: Partial<ToolCallResultEvent> = {}): ToolCallResultEvent {
  return {
    type: 'tool_call_result',
    timestamp: new Date().toISOString(),
    toolName: 'Read',
    output: 'file contents here',
    ...overrides,
  };
}

function makeSessionEnd(overrides: Partial<SessionEndEvent> = {}): SessionEndEvent {
  return {
    type: 'session_end',
    timestamp: new Date().toISOString(),
    durationSeconds: 60,
    status: 'success',
    ...overrides,
  };
}

/** Write an array of SessionEvents to a JSONL file. */
async function writeEventsJsonl(filePath: string, events: SessionEvent[]): Promise<void> {
  const jsonl = events.map(e => JSON.stringify(e)).join('\n');
  await fs.writeFile(filePath, jsonl);
}

/** Parse a JSONL file into SessionEvents, skipping malformed lines. */
function parseJsonl(content: string): SessionEvent[] {
  const parsed: SessionEvent[] = [];
  for (const line of content.split('\n')) {
    if (!line.trim()) continue;
    try { parsed.push(JSON.parse(line)); } catch { /* skip malformed */ }
  }
  return parsed;
}

afterEach(async () => {
  for (const d of tmpDirs) {
    await fs.rm(d, { recursive: true, force: true }).catch(() => {});
  }
  tmpDirs = [];
});

// ── streamLogAppend ──────────────────────────────────────────

describe('streamLogAppend', () => {
  test('appends timestamped line to log file', async () => {
    const dir = await makeTmpDir();
    const logPath = path.join(dir, 'stream.log');

    streamLogAppend(logPath, 'Test message');
    await new Promise(r => setTimeout(r, 100));

    const content = await fs.readFile(logPath, 'utf-8');
    expect(content).toContain('Test message');
    expect(content).toMatch(/^\[.*\] Test message\n$/);
  });

  test('appends multiple lines in order', async () => {
    const dir = await makeTmpDir();
    const logPath = path.join(dir, 'stream.log');

    streamLogAppend(logPath, 'First');
    await new Promise(r => setTimeout(r, 50));
    streamLogAppend(logPath, 'Second');
    await new Promise(r => setTimeout(r, 50));
    streamLogAppend(logPath, 'Third');
    await new Promise(r => setTimeout(r, 200));

    const content = await fs.readFile(logPath, 'utf-8');
    const lines = content.trim().split('\n');
    expect(lines).toHaveLength(3);
    expect(lines[0]).toContain('First');
    expect(lines[1]).toContain('Second');
    expect(lines[2]).toContain('Third');
  });

  test('does not throw when target directory does not exist (fire-and-forget)', () => {
    expect(() => {
      streamLogAppend('/nonexistent/path/stream.log', 'should not throw');
    }).not.toThrow();
  });

  test('timestamp is valid ISO 8601', async () => {
    const dir = await makeTmpDir();
    const logPath = path.join(dir, 'stream.log');

    streamLogAppend(logPath, 'ts-check');
    await new Promise(r => setTimeout(r, 100));

    const content = await fs.readFile(logPath, 'utf-8');
    const match = content.match(/^\[(.+?)\]/);
    expect(match).not.toBeNull();
    expect(new Date(match![1]).toISOString()).toBe(match![1]);
  });
});

// ── events.jsonl file creation and coexistence with stream.log ───

describe('events.jsonl coexists with stream.log', () => {
  test('both files are created in the same session directory', async () => {
    const dir = await makeTmpDir();
    const sessionDir = path.join(dir, '.forge', 'sessions', 'test-session');
    await fs.mkdir(sessionDir, { recursive: true });

    const streamLogPath = path.join(sessionDir, 'stream.log');
    const eventsPath = path.join(sessionDir, 'events.jsonl');

    await fs.writeFile(streamLogPath, '[2026-01-01T00:00:00Z] Session started\n');
    await writeEventsJsonl(eventsPath, [makeSessionStart()]);

    const streamExists = await fs.stat(streamLogPath).then(() => true).catch(() => false);
    const eventsExists = await fs.stat(eventsPath).then(() => true).catch(() => false);
    expect(streamExists).toBe(true);
    expect(eventsExists).toBe(true);
  });

  test('events.jsonl path is derived from stream.log by replacing filename', () => {
    const streamLogPath = '/repo/.forge/sessions/abc123/stream.log';
    const eventsPath = streamLogPath.replace('stream.log', 'events.jsonl');
    expect(eventsPath).toBe('/repo/.forge/sessions/abc123/events.jsonl');
  });

  test('stream.log format is unchanged (backwards compatible)', async () => {
    const dir = await makeTmpDir();
    const logPath = path.join(dir, 'stream.log');

    streamLogAppend(logPath, 'Session started (model: sonnet)');
    streamLogAppend(logPath, '$ npm test');
    streamLogAppend(logPath, 'Result: success (10 turns)');
    await new Promise(r => setTimeout(r, 200));

    const content = await fs.readFile(logPath, 'utf-8');
    const lines = content.trim().split('\n');
    expect(lines).toHaveLength(3);
    // Each line has [timestamp] prefix
    for (const line of lines) {
      expect(line).toMatch(/^\[.+?\] /);
    }
  });
});

// ── JSONL write and parse roundtrip ──────────────────────────

describe('JSONL write-parse roundtrip', () => {
  test('full session lifecycle roundtrips through JSONL', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');

    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'test-001', commandType: 'run', specPath: 'specs/auth.md' }),
      makeThinkingDelta({ content: 'Planning approach...' }),
      makeTextDelta({ content: 'I will implement authentication.' }),
      makeToolCallStart({ toolName: 'Read', toolUseId: 'tu-1', input: { file_path: 'src/auth.ts' } }),
      makeToolCallResult({ toolName: 'Read', toolUseId: 'tu-1', output: 'export function login() {}' }),
      makeToolCallStart({ toolName: 'Edit', toolUseId: 'tu-2', input: { file_path: 'src/auth.ts', old_string: '{}', new_string: '{ return true; }' } }),
      makeToolCallResult({ toolName: 'Edit', toolUseId: 'tu-2', output: 'File edited' }),
      makeToolCallStart({ toolName: 'Bash', toolUseId: 'tu-3', input: { command: 'npm test' } }),
      makeToolCallResult({ toolName: 'Bash', toolUseId: 'tu-3', output: 'All tests passed' }),
      makeSessionEnd({ numTurns: 5, costUsd: 1.50, durationSeconds: 120, status: 'success' }),
    ];

    await writeEventsJsonl(eventsPath, events);
    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = parseJsonl(content);

    expect(parsed).toHaveLength(10);

    // Verify session_start
    const start = parsed[0] as SessionStartEvent;
    expect(start.type).toBe('session_start');
    expect(start.sessionId).toBe('test-001');
    expect(start.commandType).toBe('run');
    expect(start.specPath).toBe('specs/auth.md');

    // Verify thinking_delta
    const thinking = parsed[1] as ThinkingDeltaEvent;
    expect(thinking.type).toBe('thinking_delta');
    expect(thinking.content).toBe('Planning approach...');

    // Verify text_delta
    const text = parsed[2] as TextDeltaEvent;
    expect(text.type).toBe('text_delta');
    expect(text.content).toBe('I will implement authentication.');

    // Verify tool_call_start has full input
    const toolStart = parsed[3] as ToolCallStartEvent;
    expect(toolStart.type).toBe('tool_call_start');
    expect(toolStart.toolName).toBe('Read');
    expect(toolStart.toolUseId).toBe('tu-1');
    expect(toolStart.input.file_path).toBe('src/auth.ts');

    // Verify tool_call_result has output
    const toolResult = parsed[4] as ToolCallResultEvent;
    expect(toolResult.type).toBe('tool_call_result');
    expect(toolResult.output).toBe('export function login() {}');

    // Verify session_end
    const end = parsed[9] as SessionEndEvent;
    expect(end.type).toBe('session_end');
    expect(end.numTurns).toBe(5);
    expect(end.costUsd).toBe(1.50);
    expect(end.durationSeconds).toBe(120);
    expect(end.status).toBe('success');
  });

  test('malformed JSONL lines are skipped during parsing', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');

    const lines = [
      JSON.stringify(makeSessionStart()),
      'not valid json {{{',
      '',
      JSON.stringify(makeTextDelta({ content: 'valid' })),
      '   ',
      JSON.stringify(makeSessionEnd()),
    ];
    await fs.writeFile(eventsPath, lines.join('\n'));

    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = parseJsonl(content);
    expect(parsed).toHaveLength(3);
    expect(parsed[0].type).toBe('session_start');
    expect(parsed[1].type).toBe('text_delta');
    expect(parsed[2].type).toBe('session_end');
  });

  test('empty events.jsonl returns zero events', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');
    await fs.writeFile(eventsPath, '');

    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = parseJsonl(content);
    expect(parsed).toHaveLength(0);
  });

  test('single-event file roundtrips', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');

    const event = makeSessionStart({ sessionId: 'solo' });
    await fs.writeFile(eventsPath, JSON.stringify(event));

    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = parseJsonl(content);
    expect(parsed).toHaveLength(1);
    expect((parsed[0] as SessionStartEvent).sessionId).toBe('solo');
  });
});

// ── session_start event fields ───────────────────────────────

describe('session_start event', () => {
  test('has required fields: type, timestamp, sessionId, model, prompt', () => {
    const event = makeSessionStart();
    const json = JSON.stringify(event);
    const parsed = JSON.parse(json) as SessionStartEvent;
    expect(parsed.type).toBe('session_start');
    expect(parsed.timestamp).toBeTruthy();
    expect(parsed.sessionId).toBe('test-session-001');
    expect(parsed.model).toBe('sonnet');
    expect(parsed.prompt).toBe('test prompt');
  });

  test('includes optional commandType from sessionExtra', () => {
    const event = makeSessionStart({ commandType: 'proof' });
    const parsed = JSON.parse(JSON.stringify(event)) as SessionStartEvent;
    expect(parsed.commandType).toBe('proof');
  });

  test('includes optional specPath from auditLogExtra', () => {
    const event = makeSessionStart({ specPath: 'specs/auth/login.md' });
    const parsed = JSON.parse(JSON.stringify(event)) as SessionStartEvent;
    expect(parsed.specPath).toBe('specs/auth/login.md');
  });

  test('omits undefined optional fields in JSON', () => {
    const event = makeSessionStart();
    // commandType and specPath not set
    const json = JSON.stringify(event);
    const keys = Object.keys(JSON.parse(json));
    expect(keys).not.toContain('commandType');
    expect(keys).not.toContain('specPath');
  });
});

