// ── tool_call_start event ────────────────────────────────────

describe('tool_call_start event', () => {
  test('captures full input object for Bash tool', () => {
    const event = makeToolCallStart({
      toolName: 'Bash',
      toolUseId: 'tool-bash-1',
      input: { command: 'npm test', description: 'Run test suite', timeout: 60000 },
    });
    const parsed = JSON.parse(JSON.stringify(event)) as ToolCallStartEvent;
    expect(parsed.toolName).toBe('Bash');
    expect(parsed.input.command).toBe('npm test');
    expect(parsed.input.description).toBe('Run test suite');
    expect(parsed.input.timeout).toBe(60000);
  });

  test('captures full input for Edit tool', () => {
    const event = makeToolCallStart({
      toolName: 'Edit',
      input: { file_path: '/repo/src/auth.ts', old_string: 'const a = 1;', new_string: 'const a = 2;' },
    });
    const parsed = JSON.parse(JSON.stringify(event)) as ToolCallStartEvent;
    expect(parsed.input.file_path).toBe('/repo/src/auth.ts');
    expect(parsed.input.old_string).toBe('const a = 1;');
    expect(parsed.input.new_string).toBe('const a = 2;');
  });

  test('captures full input for Grep tool', () => {
    const event = makeToolCallStart({
      toolName: 'Grep',
      input: { pattern: 'TODO|FIXME', path: 'src/', glob: '*.ts' },
    });
    const parsed = JSON.parse(JSON.stringify(event)) as ToolCallStartEvent;
    expect(parsed.input.pattern).toBe('TODO|FIXME');
    expect(parsed.input.path).toBe('src/');
    expect(parsed.input.glob).toBe('*.ts');
  });

  test('toolUseId is optional for backward compatibility', () => {
    const event = makeToolCallStart({ toolUseId: undefined });
    const json = JSON.stringify(event);
    const parsed = JSON.parse(json);
    expect(parsed.toolUseId).toBeUndefined();
  });
});

