// ── Incremental JSONL append pattern ─────────────────────────

describe('incremental JSONL append (fire-and-forget write pattern)', () => {
  test('appending lines preserves existing content', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');

    // Write initial event
    const fd1 = await fs.open(eventsPath, 'a');
    await fd1.write(JSON.stringify(makeSessionStart()) + '\n');
    await fd1.close();

    // Append more events
    const fd2 = await fs.open(eventsPath, 'a');
    await fd2.write(JSON.stringify(makeTextDelta({ content: 'hello' })) + '\n');
    await fd2.write(JSON.stringify(makeSessionEnd()) + '\n');
    await fd2.close();

    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = parseJsonl(content);
    expect(parsed).toHaveLength(3);
    expect(parsed[0].type).toBe('session_start');
    expect(parsed[1].type).toBe('text_delta');
    expect(parsed[2].type).toBe('session_end');
  });

  test('last N lines can be read efficiently for tail behavior', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');

    // Write many events
    const events: SessionEvent[] = [makeSessionStart()];
    for (let i = 0; i < 50; i++) {
      events.push(makeToolCallStart({ toolName: 'Read', input: { file_path: `file${i}.ts` } }));
      events.push(makeToolCallResult({ toolName: 'Read', output: `content ${i}` }));
    }
    events.push(makeSessionEnd());

    await writeEventsJsonl(eventsPath, events);

    // Read last 10 lines (like forge_watch does)
    const content = await fs.readFile(eventsPath, 'utf-8');
    const allLines = content.split('\n').filter(l => l.trim());
    const lastTen = allLines.slice(-10);
    expect(lastTen).toHaveLength(10);

    // Last line should be session_end
    const lastEvent = JSON.parse(lastTen[lastTen.length - 1]) as SessionEvent;
    expect(lastEvent.type).toBe('session_end');
  });

  test('session completion detected from session_end as last event', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');

    await writeEventsJsonl(eventsPath, [
      makeSessionStart(),
      makeTextDelta({ content: 'working...' }),
      makeSessionEnd({ status: 'success' }),
    ]);

    const content = await fs.readFile(eventsPath, 'utf-8');
    const allLines = content.split('\n').filter(l => l.trim());
    const lastLine = allLines[allLines.length - 1];
    const lastEvent = JSON.parse(lastLine);
    expect(lastEvent.type).toBe('session_end');
  });

  test('running session detected by absence of session_end', async () => {
    const dir = await makeTmpDir();
    const eventsPath = path.join(dir, 'events.jsonl');

    await writeEventsJsonl(eventsPath, [
      makeSessionStart(),
      makeTextDelta({ content: 'still working...' }),
      makeToolCallStart({ toolName: 'Bash', input: { command: 'npm test' } }),
    ]);

    const content = await fs.readFile(eventsPath, 'utf-8');
    const allLines = content.split('\n').filter(l => l.trim());
    const lastLine = allLines[allLines.length - 1];
    const lastEvent = JSON.parse(lastLine);
    expect(lastEvent.type).not.toBe('session_end');
  });
});
